#include<bits/stdc++.h>
using namespace std;

const long long INF = 1e18;

const int N = 21;
int n, m;

vector<pair<int, int>> g[N];

int needed = 0;

long long cc[N][(1 << N) + 5];

long long dp(int from, int mask) {

if (from == n - 1 and mask == needed) {
return 0;
}

long long &ans = cc[from][mask];

if (~ans)
return ans;
ans = INF;

for (auto v : g[from]) {
int to = v.first, weight = v.second;
ans = min(ans, weight + dp(to, mask | (1 << to)));
}

return ans;
}

void solve() {
