int u, v, w; cin >> u >> v >> w;
u--; v--;
g[u].push_back(make_pair(v, w));
g[v].push_back(make_pair(u, w));
}

needed = (1 << n) - 1;

memset(cc, -1, sizeof cc);
cout << dp(0, 1) << '\n';
}

