using namespace std;

const int INF = 1e9;
vector<pair<int, int>> g[18];
int n, m;
int dp[18][1 << 18];

int rec(int node, int mask) {
    if (node == n-1 && mask == (1 << n) - 1) {
        return 0;
    }
    if (dp[node][mask] != -1) return dp[node][mask];
    int ans = INF;
    for (auto v : g[node]) {
        int z = v.first;
        int cost = v.second;
            ans = min(ans, rec(z, mask | (1 << z)) + cost);
    }
    return dp[node][mask] = ans;
}

