import java.util.*;

class Node implements Comparable<Node> {
    int id, cost, visited;
    List<Integer> path;

    public Node(int id, int cost, int visited, List<Integer> path) {
        this.id = id;
        this.cost = cost;
        this.visited = visited;
        this.path = new ArrayList<>(path);
    }

    @Override
    public int compareTo(Node other) {
        return Integer.compare(this.cost, other.cost);
    }
}

class Graph {
    private Map<Integer, List<int[]>> adjacencyList = new HashMap<>();

    public void addEdge(int u, int v, int w) {
        if (!adjacencyList.containsKey(u)) {
            adjacencyList.put(u, new ArrayList<int[]>());
        }
        adjacencyList.get(u).add(new int[]{v, w});

        if (!adjacencyList.containsKey(v)) {
            adjacencyList.put(v, new ArrayList<int[]>());
        }
        adjacencyList.get(v).add(new int[]{u, w});
    }

    public int getMinimumTime(int n) {
        PriorityQueue<Node> queue = new PriorityQueue<>();
        queue.add(new Node(1, 0, 1, Arrays.asList(1)));

        int ub = Integer.MAX_VALUE;

        while (!queue.isEmpty()) {
            Node current = queue.poll();

            if (current.cost >= ub) break;
            if (current.visited == ((1 << n) - 1) && current.id == n) {
                ub = current.cost;
                break;
            }

            for (int[] edge : adjacencyList.get(current.id)) {
                int nei = edge[0];
                int dx = edge[1];
                int k = (1 << (nei - 1));
                if ((k & current.visited) == 0 || nei == n) {
                    List<Integer> newPath = new ArrayList<>(current.path);
                    newPath.add(nei);
                    queue.add(new Node(nei, current.cost + dx, current.visited | k, newPath));
                }
            }
        }

        return (ub == Integer.MAX_VALUE) ? -1 : ub;
    }
}

public class ScratchPad {
    public static void main(String[] args) {
        Graph graph = new Graph();
        graph.addEdge(1, 3, 20);
        graph.addEdge(2, 4, 100);
        graph.addEdge(2, 3, 40);
        graph.addEdge(2, 5, 10);
        graph.addEdge(4, 5, 15);

        int minTime = graph.getMinimumTime(5);

        if (minTime == -1) {
            System.out.println("-1");
        } else {
            System.out.println("Minimum time: " + minTime);
        }
    }
}

